CREATE POLICY "Users can update lead notes for their clients" ON public.lead_notes FOR UPDATE TO authenticated USING (client_id IN (SELECT clients.id FROM clients WHERE clients.agency_id = (SELECT profiles.agency_id FROM profiles WHERE profiles.id = auth.uid()))) WITH CHECK (client_id IN (SELECT clients.id FROM clients WHERE clients.agency_id = (SELECT profiles.agency_id FROM profiles WHERE profiles.id = auth.uid())));